const sortedKeysCache = new Map<Exclude<LanguageCode, "ko">, string[]>();
const mergedTranslationCache = new Map<Exclude<LanguageCode, "ko">, Record<string, string>>();
let activeLanguage: LanguageCode = "ko";

export function setActiveLanguage(language: LanguageCode) {
  activeLanguage = language;
}

function getKeys(language: Exclude<LanguageCode, "ko">) {
  const cached = sortedKeysCache.get(language);
  if (cached) return cached;
  const keys = Object.keys(getTranslationMap(language)).sort((a, b) => b.length - a.length);
  sortedKeysCache.set(language, keys);
  return keys;
}

function getTranslationMap(language: Exclude<LanguageCode, "ko">): Record<string, string> {
  const cached = mergedTranslationCache.get(language);
  if (cached) return cached;
  const map = language === "vi" ? { ...TRANSLATIONS.en, ...TRANSLATIONS.vi } : TRANSLATIONS[language];
  mergedTranslationCache.set(language, map);
  return map;
}

export function translateText(input: string, language: LanguageCode): string {
  if (language === "ko" || !input) return input;
  const map = getTranslationMap(language);
  const exact = map[input];
  if (exact) return exact;
  const leading = input.match(/^\s*/)?.[0] || "";
  const trailing = input.match(/\s*$/)?.[0] || "";
  const trimmed = input.trim();
  if (map[trimmed]) return leading + map[trimmed] + trailing;
  if (!/[가-힣]/.test(input)) return input;
  let output = input;
  for (const key of getKeys(language)) {
    if (key.length < 2 || !output.includes(key)) continue;
    output = output.split(key).join(map[key]);
    if (!/[가-힣]/.test(output)) break;
  }
  return output;
}

export function translateMany(items: string[], language: LanguageCode): string[] {
  return items.map((item) => translateText(item, language));
}

export function translateActiveText(input: string): string {
  return translateText(input, activeLanguage);
}

export function translateElement(root: ParentNode, language: LanguageCode) {
  if (language === "ko") return;
  const walker = document.createTreeWalker(root, NodeFilter.SHOW_TEXT, {
    acceptNode(node) {
      const parent = node.parentElement;
      if (!parent) return NodeFilter.FILTER_REJECT;
      if (parent.closest("script, style, .language-control")) return NodeFilter.FILTER_REJECT;
      if (!/[가-힣]/.test(node.nodeValue || "")) return NodeFilter.FILTER_REJECT;
      return NodeFilter.FILTER_ACCEPT;
    }
  });
  const nodes: Text[] = [];
  while (walker.nextNode()) nodes.push(walker.currentNode as Text);
  nodes.forEach((node) => { node.nodeValue = translateText(node.nodeValue || "", language); });
  const elements = root.querySelectorAll?.("[aria-label], [alt], [placeholder], [title]") || [];
  elements.forEach((element) => {
    if ((element as Element).closest(".language-control")) return;
    ["aria-label", "alt", "placeholder", "title"].forEach((attr) => {
      const value = (element as Element).getAttribute(attr);
      if (value && /[가-힣]/.test(value)) (element as Element).setAttribute(attr, translateText(value, language));
    });
  });
}
